      if (!Number.isFinite(distanceM) || distanceM <= 0) return null;
      const hit = projectSceneRayToLevelPlaneMm(
        raycaster.ray.origin,
        raycaster.ray.direction,
        elevationMm,
      );
      if (!hit) return null;
      return {
        point: hit,
        screen: clientToCanvasScreen(cx, cy),
        distanceM,
