  const stats = await page.evaluate(() => {
    const canvas = document.querySelector('[data-testid="orbit-3d-viewport"] canvas');
    if (!canvas) return { ok: false, reason: 'missing canvas' };
    const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
    if (!gl) return { ok: false, reason: 'missing gl' };
    const w = canvas.width, h = canvas.height;
    const pixels = new Uint8Array(w * h * 4);
    gl.readPixels(0, 0, w, h, gl.RGBA, gl.UNSIGNED_BYTE, pixels);
    let nonBlank = 0;
    let warmMaterial = 0;
    for (let i = 0; i < pixels.length; i += 4) {
      const r = pixels[i], g = pixels[i + 1], b = pixels[i + 2], a = pixels[i + 3];
      if (a > 0 && (r > 12 || g > 12 || b > 12)) nonBlank++;
      if (a > 0 && r > 80 && r > g * 1.05 && g > b * 1.1 && b < 120) warmMaterial++;
    }
    return { ok: true, width: w, height: h, nonBlank, warmMaterial };
  });
  await browser.close();
  if (!stats.ok || stats.nonBlank < 1000 || stats.warmMaterial < 100) {
    throw new Error(`3D canvas pixel smoke failed for ${viewport.width}x${viewport.height}: ${JSON.stringify(stats)}`);
  }
  console.log(`3D material pixel smoke ${viewport.width}x${viewport.height}:`, stats);
}

