    ? new THREE.MeshPhysicalMaterial({
        ...common,
        transmission: spec?.category === 'glass' ? (spec.key.includes('spandrel') ? 0.35 : 0.9) : 0,
        thickness: spec?.category === 'glass' ? 0.012 : 0,
        ior: spec?.category === 'glass' ? 1.5 : 1.45,
