    expect(material.normalMap?.name).toBe('asset://project/brick/normal');
    expect(material.bumpMap).toBeFalsy();
    expect(material.roughnessMap?.name).toBe('asset://project/brick/roughness');
    expect(material.metalnessMap?.name).toBe('asset://project/brick/metal');
    expect(loads).not.toContain('asset://project/brick/height');
  });

  it('disposes cached textures', () => {
    const textureManager = stubTextureManager();
